var init_runtime_api_reference = __esm({
  "../../docs/runtime-api-reference.md"() {
    runtime_api_reference_default = "# GeneXus 18 Runtime JavaScript API Reference\n\nThe GeneXus runtime injects `window.gx` into all application pages. Inside UC `AfterShow` scripts, `window.gx` is available with the APIs documented here.\n\n> **Important**: These are internal GeneXus runtime APIs. Behavior may vary between GeneXus versions. Verify against your specific GeneXus version and compiler target (Java/Tomcat, .NET, etc.). Always use safe access patterns: `if (window.gx && gx.dom) { ... }`.\n\n---\n\n## Safe Access Pattern\n\nAlways guard against missing APIs:\n\n```javascript\n// \u2705 Safe \u2014 works even if API is unavailable\nfunction safeAddClass(el, cls) {\n    if (window.gx && gx.dom && gx.dom.addClass) {\n        gx.dom.addClass(el, cls);\n    } else {\n        el.classList.add(cls);  // fallback to native\n    }\n}\n```\n\n---\n\n## `gx.dom` \u2014 DOM Utilities\n\nDOM manipulation helpers available in the GeneXus runtime context.\n\n```javascript\n// Class manipulation\ngx.dom.addClass(element, 'my-class');\ngx.dom.removeClass(element, 'my-class');\ngx.dom.hasClass(element, 'my-class');   // returns boolean\ngx.dom.toggleClass(element, 'my-class');\n\n// Safe innerHTML injection (uses GeneXus sanitization)\ngx.dom.setInnerHtml(element, '<span>content</span>');\n\n// HTML escaping\nvar safe = gx.dom.encode('string with <special> &chars');\n// \u2192 'string with &lt;special&gt; &amp;chars'\n```\n\n### Usage Example\n\n```javascript\n(function () {\n    var self = this;\n    var ucid = this.ucid;\n\n    var el = document.querySelector('[data-ucid=\"' + ucid + '\"]');\n    if (!el) return;\n    if (el.getAttribute('data-uc-init') === '1') return;\n    el.setAttribute('data-uc-init', '1');\n\n    var encode = (window.gx && gx.dom && gx.dom.encode)\n        ? function(s) { return gx.dom.encode(s == null ? '' : String(s)); }\n        : function(s) {\n            return String(s == null ? '' : s)\n                .replace(/&/g,'&amp;').replace(/</g,'&lt;')\n                .replace(/>/g,'&gt;').replace(/\"/g,'&quot;');\n        };\n\n    var panel = el.querySelector('[data-part=\"panel\"]');\n    var html = '<button class=\"item\">' + encode(self.Label) + '</button>';\n\n    if (window.gx && gx.dom && gx.dom.setInnerHtml) {\n        gx.dom.setInnerHtml(panel, html);\n    } else {\n        panel.innerHTML = html;\n    }\n\n}).call(this);\n```\n\n---\n\n## `gx.evt` \u2014 Event Utilities\n\nCross-browser event handling utilities.\n\n```javascript\n// Attach event listener\ngx.evt.attach(element, 'click', function(e) {\n    // handler\n});\n\n// Stop event propagation\ngx.evt.stopPropagation(e);\n\n// Get event source (target element)\nvar target = gx.evt.source(e);\n\n// gx.evt.on_ready \u2014 runs when DOM is ready\ngx.evt.on_ready(function() {\n    // safe to access DOM here\n});\n```\n\n### Usage Example\n\n```javascript\nvar trigger = el.querySelector('[data-part=\"trigger\"]');\nvar panel   = el.querySelector('[data-part=\"panel\"]');\n\nfunction open() {\n    if (window.gx && gx.dom) {\n        gx.dom.addClass(trigger, 'btn--open');\n        gx.dom.addClass(panel, 'dropdown--open');\n    }\n    trigger.setAttribute('aria-expanded', 'true');\n}\n\nfunction close() {\n    if (window.gx && gx.dom) {\n        gx.dom.removeClass(trigger, 'btn--open');\n        gx.dom.removeClass(panel, 'dropdown--open');\n    }\n    trigger.setAttribute('aria-expanded', 'false');\n}\n\nif (window.gx && gx.evt) {\n    gx.evt.attach(trigger, 'click', function(e) {\n        gx.evt.stopPropagation(e);\n        if (gx.dom.hasClass(panel, 'dropdown--open')) close(); else open();\n    });\n\n    gx.evt.attach(document, 'click', function(e) {\n        var src = gx.evt.source(e);\n        if (src && !el.contains(src)) close();\n    });\n}\n```\n\n---\n\n## `gx.fx.obs` \u2014 Pub/Sub (Observable Events)\n\nThe GeneXus runtime pub/sub system for JavaScript \u2194 GeneXus communication.\n\n```javascript\n// Publish an event (JavaScript \u2192 GeneXus)\ngx.fx.obs.notify('EventName.action', 'parameter-value');\n\n// Subscribe to an event (JavaScript \u2192 JavaScript)\ngx.fx.obs.suscribe('EventName.action', function(param) {\n    // handler receives the parameter\n});\n\n// Unsubscribe\ngx.fx.obs.unsuscribe('EventName.action', handlerReference);\n```\n\n> Note: GeneXus spells it `suscribe` (not `subscribe`) \u2014 this is not a typo.\n\n### JS \u2192 GeneXus Communication\n\nThis is the recommended way to trigger GeneXus events from JavaScript:\n\n```javascript\n// In UC AfterShow script\nfunction notifyGeneXus(action, param) {\n    if (window.gx && gx.fx && gx.fx.obs && gx.fx.obs.notify) {\n        gx.fx.obs.notify('MyModule.action', param);\n    }\n}\n```\n\n```genexus\n// In WebPanel \u2014 subscribe to the event\nEvent 'MyModule.action'\n    // &EventParam receives the value passed from JS\n    Do 'HandleAction'\nEndEvent\n```\n\n### JS \u2192 JS Communication (between UCs)\n\n```javascript\n// UC A publishes\ngx.fx.obs.notify('navigation.itemSelected', itemId);\n\n// UC B listens\ngx.fx.obs.suscribe('navigation.itemSelected', function(id) {\n    // react to selection in UC A\n});\n```\n\n---\n\n## `gx.http.storage` \u2014 Storage Abstractions\n\nAbstractions over browser session/local storage.\n\n```javascript\n// Session storage\ngx.http.storage.setSessionValue('key', 'value');\nvar val = gx.http.storage.getSessionValue('key');\n\n// Local storage\ngx.http.storage.setLocalValue('key', 'value');\nvar val = gx.http.storage.getLocalValue('key');\n\n// Remove\ngx.http.storage.removeSessionValue('key');\ngx.http.storage.removeLocalValue('key');\n```\n\n### Usage Example\n\n```javascript\n// Cache user preference\nvar pref = gx.http.storage.getSessionValue('nav-collapsed');\nif (pref === 'true') {\n    collapseNav();\n}\n\n// Save preference on toggle\nfunction toggleNav() {\n    var collapsed = gx.dom.hasClass(navEl, 'nav--collapsed');\n    gx.dom.toggleClass(navEl, 'nav--collapsed');\n    gx.http.storage.setSessionValue('nav-collapsed', String(!collapsed));\n}\n```\n\n---\n\n## `gx.grid` \u2014 Grid Operations\n\nAPIs for interacting with GeneXus Grid controls from JavaScript.\n\n```javascript\n// Get grid element by internal name\nvar grid = gx.grid.getGrid('GridName');\n\n// Refresh grid data\ngx.grid.refresh('GridName');\n\n// Get current page\nvar page = gx.grid.getCurrentPage('GridName');\n\n// Navigate pages\ngx.grid.nextPage('GridName');\ngx.grid.prevPage('GridName');\ngx.grid.firstPage('GridName');\ngx.grid.lastPage('GridName');\n```\n\n### UC Injecting into Grid Footer\n\nA common pattern is to find a GeneXus grid in the DOM and inject totals into the `<tfoot>`:\n\n```javascript\n// GeneXus grid internal names are UPPERCASE \u2014 use case-insensitive search\nvar gridId    = (self.GridName || '').toUpperCase();\nvar container = document.querySelector(\"[id*='\" + gridId + \"' i]\");\nvar table     = container ? container.querySelector('table') : null;\nvar tfoot     = table ? table.querySelector('tfoot') : null;\n\nif (tfoot) {\n    var row = '<tr><td colspan=\"5\" class=\"grid-footer__totals\">';\n    row += esc(self.TotalLabel) + ': ' + esc(self.TotalValue);\n    row += '</td></tr>';\n    tfoot.innerHTML = row;\n}\n```\n\n---\n\n## `gx.popup` \u2014 Popup/Modal Management\n\nAPIs for controlling GeneXus popup windows.\n\n```javascript\n// Close current popup\ngx.popup.close();\n\n// Close popup by ID\ngx.popup.close('popupId');\n\n// Check if inside a popup\nvar inPopup = gx.popup.isPopup();\n```\n\n### Detecting GeneXus Popup Open/Close\n\nGeneXus popups are injected as elements with IDs starting with `gxp`. Use a MutationObserver to react:\n\n```javascript\nvar observer = new MutationObserver(function(mutations) {\n    mutations.forEach(function(m) {\n        m.addedNodes.forEach(function(node) {\n            if (node.nodeType === 1) {\n                var id  = (node.id || '');\n                var cls = (node.className || '').toString();\n                if (id.indexOf('gxp') > -1 || cls.indexOf('gx-popup') > -1) {\n                    // A GeneXus popup opened \u2014 close any floating panels\n                    closeDropdown();\n                }\n            }\n        });\n    });\n});\nobserver.observe(document.body, { childList: true, subtree: false });\n```\n\n---\n\n## `gx.fn` \u2014 Function Utilities\n\nGeneral utility functions available in the GeneXus runtime.\n\n```javascript\n// Type checking\ngx.fn.isFunction(fn);   // returns boolean\ngx.fn.isString(val);    // returns boolean\ngx.fn.isArray(val);     // returns boolean\n\n// Object utilities\ngx.fn.extend(target, source);  // shallow merge\n\n// String utilities\ngx.fn.trim(str);        // trim whitespace\n```\n\n---\n\n## Floating Dropdown Positioning Pattern\n\nA reusable pattern for positioning a floating dropdown panel below its trigger element:\n\n```javascript\nfunction positionDropdown(triggerEl, panelEl) {\n    var rect = triggerEl.getBoundingClientRect();\n    panelEl.style.position = 'fixed';\n    panelEl.style.top      = (rect.bottom + 4) + 'px';\n    panelEl.style.left     = rect.left + 'px';\n    panelEl.style.width    = rect.width + 'px';\n    panelEl.style.zIndex   = '9999';\n}\n\n// Close on scroll (critical for fixed-positioned dropdowns)\n$(window).off('scroll.ns_' + ucid).on('scroll.ns_' + ucid, closeDropdown);\n$(document).off('scroll.ns_' + ucid).on('scroll.ns_' + ucid, '*', closeDropdown);\n```\n\n---\n\n## Injecting CSS Dynamically (Keyframe Workaround)\n\nWhen CSS `@keyframes` or `::-webkit-scrollbar` don't apply from the UC `<style>` block (iframe context), inject via JavaScript:\n\n```javascript\nfunction injectCss(id, css) {\n    if (document.getElementById(id)) return;  // guard \u2014 only inject once\n    var style = document.createElement('style');\n    style.id = id;\n    style.textContent = css;\n    document.head.appendChild(style);\n}\n\ninjectCss('my-uc-keyframes-' + ucid, [\n    '@keyframes my-uc-spin {',\n    '  from { transform: rotate(0deg); }',\n    '  to { transform: rotate(360deg); }',\n    '}'\n].join(''));\n```\n\n---\n\n## jQuery in GeneXus Context\n\nGeneXus 18 includes jQuery globally. `$` is available in UC scripts.\n\n**Always use `.off()` before `.on()` to prevent listener accumulation:**\n\n```javascript\n// \u2705 CORRECT \u2014 prevents duplicate handlers after Refresh\n$('#my-el-' + ucid).off('click').on('click', function(e) {\n    // handler\n});\n\n// Document-level events \u2014 use namespace for safe cleanup\n$(document).off('click.ns_' + ucid).on('click.ns_' + ucid, function(e) {\n    if (!el.contains(e.target)) close();\n});\n\n// \u274C WRONG \u2014 accumulates handlers on each Refresh\n$('#my-el-' + ucid).on('click', function(e) { ... });\n```\n";
  }
});

// ../../docs/common-pitfalls.md
var common_pitfalls_default;
var init_common_pitfalls = __esm({
  "../../docs/common-pitfalls.md"() {
    common_pitfalls_default = "# Common Pitfalls in GeneXus User Controls\n\nReal-world traps found in production GeneXus codebases. Ordered by recurrence frequency.\n\n---\n\n## 1. Re-init guard with `getAttribute` requires explicit comparison\n\nThe most common guard bug. Using a falsy check instead of a strict equality check inverts the logic.\n\n```javascript\n// \u274C WRONG \u2014 this guard NEVER blocks re-init\n// getAttribute returns null when attribute is absent, which is falsy\n// So the \"if (!getAttribute)\" fires on EVERY AfterShow call (null is falsy)\nvar el = document.getElementById('my-uc-' + ucid);\nif (!el.getAttribute('data-init')) return;  // backwards! allows re-run when null\nel.setAttribute('data-init', '1');\n\n// \u2705 CORRECT \u2014 strict string comparison\nvar el = document.querySelector('[data-ucid=\"' + ucid + '\"]');\nif (!el) return;\nif (el.getAttribute('data-init') === '1') return;  // blocks on second run\nel.setAttribute('data-init', '1');\n// only reaches here on first execution per instance\n```\n\n**Why it matters**: Without the guard, event listeners accumulate on every postback. A button ends up firing 2\xD7, 3\xD7, N\xD7 clicks.\n\n---\n\n## 2. XSS via `innerHTML` without escaping\n\nInjecting untrusted data directly into `innerHTML` is an XSS vector and also causes HTML parse errors when the data contains `<`, `>`, `\"`, or `&`.\n\n```javascript\n// \u274C WRONG \u2014 breaks with special characters, enables XSS\npanel.innerHTML = '<span>' + item.label + '</span>';\n\n// \u2705 CORRECT \u2014 always escape before innerHTML\nfunction esc(s) {\n    return String(s == null ? '' : s)\n        .replace(/&/g, '&amp;')\n        .replace(/</g, '&lt;')\n        .replace(/>/g, '&gt;')\n        .replace(/\"/g, '&quot;');\n}\n\npanel.innerHTML = '<span>' + esc(item.label) + '</span>';\n```\n\nApply `esc()` to every user-controlled value that goes into `innerHTML`. No exceptions.\n\n---\n\n## 3. `textContent` displays HTML entities literally\n\nWhen GeneXus injects HTML-encoded content into a div, reading `innerHTML` gives you `&amp;`, `&lt;`, etc. as literal strings. `textContent` does not decode them \u2014 you need to use a temporary DOM element.\n\n```javascript\n// Scenario: GeneXus injected \"&lt;script&gt;\" into a data div\nvar dataDiv = document.getElementById('uc-data-' + ucid);\n\n// \u274C WRONG \u2014 dataDiv.textContent returns \"&lt;script&gt;\" (literal entities)\nvar text = dataDiv.textContent;\n\n// \u2705 CORRECT \u2014 decode via temporary div\nfunction decodeHtml(s) {\n    var d = document.createElement('div');\n    d.innerHTML = s;\n    return d.textContent || d.innerText || '';\n}\n\nvar text = decodeHtml(dataDiv.innerHTML);\n```\n\nThis is the standard browser technique for decoding HTML entities.\n\n---\n\n## 4. Manual JSON construction in GeneXus always breaks\n\nManually concatenating JSON strings in GeneXus code fails as soon as a field contains quotes, accents, newlines, or any special character.\n\n```genexus\n// \u274C WRONG \u2014 breaks with any special character in &Nome or &Id\nUCMyControl.ItemsJson = !'[{\"id\":\"' + &Id + '\",\"label\":\"' + &Nome + '\"}]'\n\n// \u2705 CORRECT \u2014 use SDT.ToJson() which handles all escaping\n&SdtItem.Id    = &Id\n&SdtItem.Label = &Nome\n&SdtCollection.Add(&SdtItem)\nUCMyControl.ItemsJson = &SdtCollection.ToJson()\n```\n\n`SDT.ToJson()` is the only safe way to build JSON in GeneXus. Manual concatenation is a time bomb.\n\n---\n\n## 5. Typos in SDT field names propagate silently\n\nIf you mistype an SDT field name in JavaScript (e.g., `item.Lable` instead of `item.Label`), the access returns `undefined`. JavaScript does not throw an error \u2014 you just get empty values everywhere and no stack trace to help.\n\n```javascript\n// Suppose the JSON has: [{\"id\": \"1\", \"label\": \"My Item\"}]\nvar items = JSON.parse(raw);\n\n// \u274C WRONG \u2014 typo, returns undefined silently\nvar label = items[0].Lable;   // undefined\n\n// \u2705 CORRECT \u2014 match SDT field names exactly\nvar label = items[0].label;   // \"My Item\"\n```\n\n**Best practice**: log the raw JSON during development to verify exact field names before writing accessor code.\n\n```javascript\n// Temporary debug \u2014 remove before delivery\nconsole.log('UC data:', JSON.stringify(items[0]));\n```\n\n---\n\n## 6. For Each loops need explicit handling for empty collections\n\nIn GeneXus, the `&last` variable used for comma separation must be initialized to `-1`. If you initialize it to `0` and the collection is empty, the last-item logic silently produces wrong output.\n\n```genexus\n// \u274C WRONG \u2014 &last = 0 causes off-by-one when collection is empty\n&last = 0\nFor Each Item\n    ...\nEndFor\n\n// \u2705 CORRECT \u2014 initialize to -1, update inside the loop\n&last = -1\nFor Each Item\n    &last = Item.Position\nEndFor\n\n// Also add explicit empty-collection handling:\nIf &Collection.Count = 0\n    UCMyControl.ItemsJson = !'[]'\n    Return\nEndIf\n```\n\n---\n\n## 7. `Iif` branches are swapped\n\nA classic GeneXus mistake: swapping the \"true\" and \"false\" branches in `Iif`.\n\n```genexus\n// Signature: Iif(condition, valueIfTrue, valueIfFalse)\n\n// \u274C WRONG \u2014 &Nome is empty, so IsEmpty is true, but we're returning &Nome (empty)\nUCMyControl.Label = Iif(IsEmpty(&Nome), &Nome, !'Default')\n//                                       \u2191 true branch runs when &Nome IS empty \u2192 returns \"\"\n\n// \u2705 CORRECT \u2014 when &Nome is empty, return the fallback; otherwise return &Nome\nUCMyControl.Label = Iif(IsEmpty(&Nome), !'Default', &Nome)\n//                                        \u2191 true branch = \"it IS empty\" \u2192 use default\n```\n\n**Mnemonic**: `Iif(condition, THEN, ELSE)` \u2014 read it as: \"IF this is true, THEN use A, ELSE use B.\"\n\n---\n\n## 8. Pass only the modifier class, not the full class string\n\nWhen a UC property controls visual state (e.g., a color variant), pass only the modifier suffix. The UC should compose the full class name internally.\n\n```genexus\n// \u274C WRONG \u2014 passing the full class name couples the caller to UC internals\nUCMyControl.Variant = !'my-button my-button--primary'\n\n// \u2705 CORRECT \u2014 pass only the modifier value\nUCMyControl.Variant = !'primary'\n```\n\nIn the UC JavaScript, compose the class:\n\n```javascript\nvar variant = control.Variant || 'default';\nbtnEl.className = 'my-button my-button--' + variant;\n```\n\nThis way, renaming the CSS class only requires changing the UC \u2014 not all WebPanels that use it.\n\n---\n\n## 9. Old code left in `Event Start` after extracting to a Sub\n\nWhen you refactor initialization code from `Event Start` into a dedicated `Sub`, the original code must be removed from `Event Start`. Leaving it there means the logic runs twice: once in Start and once when the Sub is called.\n\n```genexus\n// \u274C WRONG after refactor \u2014 MontaControle runs twice\nEvent Start\n    // code you meant to move...\n    UCMyControl.ucid  = !'MyId'    // still here from before refactor\n    UCMyControl.Label = &Nome      // still here from before refactor\n    Do 'MontaControle'             // also runs it via Sub\nEndEvent\n\n// \u2705 CORRECT \u2014 remove from Start after extracting\nEvent Start\n    Do 'MontaControle'\nEndEvent\n\nSub 'MontaControle'\n    UCMyControl.ucid  = !'MyId'\n    UCMyControl.Label = &Nome\nEndSub\n```\n\n---\n\n## 10. VarChar fields for URLs need minimum 500 characters\n\nGeneXus default VarChar length is often 20 or 50. Modern URLs (with query parameters, OAuth tokens, redirect URLs) routinely exceed 200 characters. Always declare URL fields with sufficient length.\n\n```genexus\n// \u274C WRONG \u2014 truncates long URLs silently\n&Url     : VarChar(100)\n&RedirectUrl : VarChar(50)\n\n// \u2705 CORRECT \u2014 use at least 500 for any URL field\n&Url         : VarChar(500)\n&RedirectUrl : VarChar(1000)  // OAuth redirect URLs can be very long\n&ApiEndpoint : VarChar(500)\n```\n\nSilent truncation is one of the hardest bugs to diagnose because the GeneXus compiler does not warn you \u2014 it just cuts the string at the declared length.\n\n---\n\n## Quick Reference\n\n| # | Symptom | Root Cause | Fix |\n|---|---------|-----------|-----|\n| 1 | Event fires N times on one click | Guard uses `!getAttribute()` (inverted) | Use `=== '1'` explicit comparison |\n| 2 | HTML broken / XSS risk | `innerHTML` with unescaped user data | `esc()` every value before innerHTML |\n| 3 | `&amp;` appears as literal text | `textContent` on HTML-encoded content | `decodeHtml()` via temp div |\n| 4 | JSON errors with special chars | Manual string concatenation | `SDT.ToJson()` always |\n| 5 | Empty values, no error | SDT field name typo in JS | Log raw JSON; match names exactly |\n| 6 | Last-item logic wrong on empty list | `&last = 0` initialization | Initialize to `-1` |\n| 7 | Wrong value in Iif branch | Condition result inverted | Read as \"IF true THEN ... ELSE ...\" |\n| 8 | Style breaks when CSS renamed | Full class in property | Pass only modifier suffix |\n| 9 | Init runs twice, events double | Old code left in Start after refactor | Remove original after extracting Sub |\n| 10 | URL truncated silently | VarChar too short | VarChar(500) minimum for URLs |\n";
  }
});

